import{_ as a,o as t,c as s,a3 as o}from"./chunks/framework.CjquFG0V.js";const c=JSON.parse('{"title":"65. Compassionate Leave","description":"","frontmatter":{"title":"65. Compassionate Leave","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["leave","compassionate-leave","preliminary","definitions"]},"headers":[],"relativePath":"ebas/mspp/leave/65-compassionate-leave.md","filePath":"ebas/mspp/leave/65-compassionate-leave.md"}'),n={name:"ebas/mspp/leave/65-compassionate-leave.md"};function r(i,e,p,l,m,d){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="_65-compassionate-leave" tabindex="-1">65. Compassionate Leave <a class="header-anchor" href="#_65-compassionate-leave" aria-label="Permalink to &quot;65. Compassionate Leave&quot;">​</a></h1><p><strong>65.1</strong> Paid Leave Entitlement</p><p><strong>a.</strong> A full-time or part-time Employee is entitled to two days paid Compassionate Leave per occasion when:</p><p><strong>(i)</strong> a member of the Employee&#39;s immediate family or household: <strong>(A)</strong> contracts or develops a personal illness that poses a serious threat to their life; or <strong>(B)</strong> sustains a personal injury that poses a serious threat to their life; or <strong>(C)</strong> dies; or <strong>(D)</strong> loses a pregnancy after 20 weeks gestation; or</p><p><strong>(ii)</strong> The Employee or their partner loses a pregnancy.</p><p><strong>b.</strong> An Employee may take up to an additional two days paid compassionate leave per annum in addition to the above entitlement.</p><p>3453-8976-3100v1PART 8: LEAVE OF ABSENCE AND PUBLIC HOLIDAYS</p><p><strong>c.</strong> An Employee is entitled to use accumulated personal leave as paid Compassionate Leave up to an additional two days annually (pro-rata for part- time Employees) when a member of the Employee&#39;s immediate family or household in Australia dies/is seriously ill</p><p><strong>65.2</strong> Unpaid Compassionate leave</p><p><strong>a.</strong> Where an Employee has exhausted all entitlements under clause 65.1, an Employee may take up to 4 days unpaid Compassionate Leave. Additional unpaid leave may then be taken by agreement with the Employer.</p><p><strong>b.</strong> A casual Employee may take 2 days unpaid Compassionate Leave per occasion when:</p><p><strong>(i)</strong> A member of the employee’s immediate family or household: <strong>(A)</strong> contracts or develops a personal illness or sustains a personal injury that poses a serious threat to their life; <strong>(B)</strong> dies; <strong>(C)</strong> loses a pregnancy after 20 weeks gestation;</p><p><strong>(ii)</strong> The Employee or their partner loses a pregnancy.</p><p><strong>c.</strong> Nothing under this clause limits an Employee&#39;s ability to take personal leave pursuant to <a href="/eba/ebas/mspp/leave/64-personal-carer-s-leave.html">clause 64</a>.</p><p>Plain language terms: bereavement leave, funeral leave.</p>',15)])])}const h=a(n,[["render",r]]);export{c as __pageData,h as default};
